// 네이버 검색광고 API HMAC-SHA256 서명 생성
const crypto = require('crypto');

const API_KEY = $env.NAVER_SA_API_KEY;
const SECRET_KEY = $env.NAVER_SA_SECRET_KEY;
const CUSTOMER_ID = $env.NAVER_SA_CUSTOMER_ID;

// 쿼리 파라미터에서 기간 가져오기
const query = $input.first().json.query || {};
const startDate = query.start || new Date(Date.now() - 30*24*60*60*1000).toISOString().split('T')[0];
const endDate = query.end || new Date().toISOString().split('T')[0];

// 서명 생성
const timestamp = Date.now().toString();
const method = 'GET';
const uri = '/ncc/campaigns';
const message = `${timestamp}.${method}.${uri}`;
const signature = crypto.createHmac('sha256', SECRET_KEY).update(message).digest('base64');

return [{
  json: {
    timestamp,
    signature,
    apiKey: API_KEY,
    customerId: CUSTOMER_ID,
    startDate,
    endDate,
    uri
  }
}];

// 캠페인 목록에서 성과 데이터 조회를 위한 서명 생성
const crypto = require('crypto');

const API_KEY = $env.NAVER_SA_API_KEY;
const SECRET_KEY = $env.NAVER_SA_SECRET_KEY;
const CUSTOMER_ID = $env.NAVER_SA_CUSTOMER_ID;

// 이전 노드에서 캠페인 목록 가져오기
const campaigns = $input.first().json.body || $input.first().json;
const campaignList = Array.isArray(campaigns) ? campaigns : [];

// 이전 서명 노드에서 기간 정보 가져오기 (items[0]에서)
const prevData = $('서명 생성').first().json;
const startDate = prevData.startDate;
const endDate = prevData.endDate;

const campaignIds = campaignList.map(c => c.nccCampaignId);
const campaignMap = {};
campaignList.forEach(c => { campaignMap[c.nccCampaignId] = c; });

// stats 호출용 서명
const timestamp = Date.now().toString();
const method = 'GET';
const uri = '/stats';
const message = `${timestamp}.${method}.${uri}`;
const signature = crypto.createHmac('sha256', SECRET_KEY).update(message).digest('base64');

return [{
  json: {
    timestamp,
    signature,
    apiKey: API_KEY,
    customerId: CUSTOMER_ID,
    campaignIds,
    campaignMap,
    startDate,
    endDate
  }
}];

// 캠페인 목록 + 성과 데이터 조합하여 최종 응답 생성
const prevData = $('Stats 서명 생성').first().json;
const campaignMap = prevData.campaignMap;

const statsResponse = $input.first().json.body || $input.first().json;
const statsData = statsResponse.data || (Array.isArray(statsResponse) ? statsResponse : []);

const output = statsData.map(s => {
  const camp = campaignMap[s.id] || {};
  return {
    id: s.id,
    name: camp.name || '',
    type: camp.campaignTp || '',
    account: 'SA',
    status: camp.status || '',
    impressions: s.impCnt || 0,
    clicks: s.clkCnt || 0,
    cost: s.salesAmt || 0,
    ctr: s.ctr || 0,
    cpc: s.cpc || 0,
    conversions: s.ccnt || 0,
    convValue: s.convAmt || 0,
    purchaseCount: 0,
    purchaseAmount: 0,
    cartCount: 0
  };
});

return [{ json: { campaigns: output } }];
